import time
from vex_sdk import VexSpan

@VexSpan.track('agent_retry_loop')
def safe_retry_agent(agent, query, max_retries=3):
    for attempt in range(max_retries):
        with VexSpan.current().set_tag('retry_attempt', attempt):
            try:
                return agent.run(query)
            except Exception:
                if attempt == max_retries - 1:
                    VexSpan.current().set_error('max_retries_exceeded')
                    raise
                time.sleep(2 ** attempt)

