from pydantic_ai import Agent
from pydantic import ValidationError
from vex_sdk.result_validator import SemanticValidator

class FuzzyValidator:
    def __init__(self):
        self.semantic = SemanticValidator()

    def __call__(self, output: dict):
        try:
            return ResearchReport.model_validate(output)
        except ValidationError:
            # Fallback: semantic validation
            if self.semantic.validate(output, 'research_report'):
                return ResearchReport.model_validate_dict(self.semantic.repair(output))
            raise

agent = Agent('researcher', result_validator=FuzzyValidator())

from pydantic_ai import Agent, SessionContext

from vex_sdk.middleware import ContextMiddleware

class AgentWithContext(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.middleware.append(ContextMiddleware())

    async def _execute_tool(self, tool_call):
        # Ensure session context flows to nested calls
        ctx = SessionContext.current()
        if ctx:
            tool_call.context = ctx.dict()
        return await super()._execute_tool(tool_call)

researcher = AgentWithContext('researcher')

from pydantic_ai import Agent
from typing import Iterator

class ResumableStreamer:
    def __init__(self, agent: Agent):
        self.agent = agent
        self.buffer = []

    def stream_structured(self, query: str) -> Iterator:
        for chunk in self.agent.stream_structured(query):
            self.buffer.append(chunk)
            # Progressive validation
            try:
                partial = ''.join(map(str, self.buffer[-10:]))
                yield ResearchReport.model_validate_json(partial)
            except ValidationError:
                continue  # Buffer until valid
